      "path": "src/modules/members/routes.js",
      "content": "const express = require('express');
const membersService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_INPUT', 'Both userId and role are required');
  }
  try {
    const member = await membersService.addMember(req.params.projectId, userId, role);
    res.json({ member });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.get('/', async (req, res) => {
  try {
    const members = await membersService.getAllMembers(req.params.projectId);
    res.json({ members });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;"
    },
    {
      "path": "src/modules/members/service.js",
      "content": "const projectsService = require('../projects/service');

const addMember = async (projectId, userId, role) => {
  const project = projectsService.projectsStore.find(p => p.id === projectId);
  if (!project) {
    throw new Error('Project not found');
  }
  const member = { id: userId, role };
  project.members.push(member);
  return member;
};

const getAllMembers = async (projectId) => {
  const project = projectsService.projectsStore.find(p => p.id === projectId);
  if (!project) {
    throw new Error('Project not found');
  }
  return project.members;
};

module.exports = { addMember, getAllMembers };"
