      "path": "src/modules/comments/service.js",
      "content": "const tasksService = require('../tasks/service');

const addComment = async (projectId, taskId, content) => {
  const project = tasksService.projectsStore.find(p => p.id === projectId);
  if (!project) {
    throw new Error('Project not found');
  }
  const task = project.tasks.find(t => t.id === taskId);
  if (!task) {
    throw new Error('Task not found');
  }
  const comment = { id: tasksService.randomUUID(), content };
  task.comments = task.comments || [];
  task.comments.push(comment);
  return comment;
};

const getAllComments = async (projectId, taskId) => {
  const project = tasksService.projectsStore.find(p => p.id === projectId);
  if (!project) {
    throw new Error('Project not found');
  }
  const task = project.tasks.find(t => t.id === taskId);
  if (!task) {
    throw new Error('Task not found');
  }
  return task.comments || [];
};

module.exports = { addComment, getAllComments };"
